+const COPILOT_VENDOR_DIR = 'vendor/copilot';
+const SUPPORTED_PLATFORMS = ['darwin', 'linux', 'win32'];
+
+function getVendorBinaryName(): string | undefined {
+  if (!SUPPORTED_PLATFORMS.includes(process.platform)) return undefined;
